import { GoogleGenAI, Type } from "@google/genai";
import { MenuItem } from "../types";

export const getSushiRecommendation = async (userMood: string, menuItems: MenuItem[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare a concise menu context for the AI
  const menuContext = menuItems.map(item => 
    `- ${item.name}: ${item.description} ($${item.price})`
  ).join('\n');

  const prompt = `Actúa como el Sommelier experto de Kayso Sushi, un delivery líder en San Miguel, Argentina. 
  Tu objetivo es recomendar el plato ideal del menú basado en lo que el cliente tiene ganas.

  MENÚ DISPONIBLE:
  ${menuContext}

  SOLICITUD DEL CLIENTE: "${userMood}"

  REGLAS:
  1. Sé amable, canchero y breve (máximo 3 oraciones).
  2. Mencioná 1 o 2 opciones específicas del menú que coincidan con su antojo.
  3. Si mencionás precios, usá el formato $X.XXX.
  4. Si no hay nada que coincida exactamente, recomendá el "Combinado Premium" o el "Kayso Roll".
  5. Respondé en español rioplatense (usá "che", "tenés", "pedite").`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        temperature: 0.7,
        topP: 0.95,
        maxOutputTokens: 200,
      }
    });

    return response.text || "Che, se me complicó la cocina. ¡Pero te recomiendo el Combinado Premium que nunca falla!";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "¡Hola! Estoy un poco ocupado en la barra. Te recomiendo probar nuestro Kayso Roll, ¡es la estrella de la casa!";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { getSushiRecommendation } from '../services/geminiService';
import { MessageSquare, Send, Loader2, Sparkles, X } from 'lucide-react';
import { MenuItem } from '../types';

interface SushiAssistantProps {
    menuItems: MenuItem[];
}

export const SushiAssistant: React.FC<SushiAssistantProps> = ({ menuItems }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [response, isLoading]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    setIsLoading(true);
    const userInput = input;
    setInput('');

    const result = await getSushiRecommendation(userInput, menuItems);

    setResponse(result);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="bg-gray-900 border border-kayso-orange/30 rounded-2xl shadow-2xl mb-4 w-80 md:w-96 overflow-hidden animate-float">
          {/* Header */}
          <div className="bg-gradient-to-r from-kayso-orange to-red-700 p-4 flex items-center justify-between">
            <div className="flex items-center gap-2">
                <div className="bg-white/20 p-2 rounded-lg backdrop-blur-sm">
                    <Sparkles size={18} className="text-white" />
                </div>
                <div>
                  <h3 className="font-bold text-white text-sm">Kayso Sommelier IA</h3>
                  <p className="text-[10px] text-white/80 uppercase font-bold">Online ahora</p>
                </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/80 hover:text-white transition-colors">
              <X size={20} />
            </button>
          </div>

          {/* Body */}
          <div ref={scrollRef} className="p-4 max-h-80 overflow-y-auto bg-kayso-dark/50 scrollbar-hide">
            {!response && !isLoading && (
               <div className="bg-gray-800 rounded-xl p-3 border border-gray-700 mb-2">
                 <p className="text-gray-200 text-sm">
                   ¡Hola! 👋 Soy tu guía personal de Kayso. ¿No sabés qué pedir? Decime qué tenés ganas (algo fresco, picante, veggie...) y te armo el pedido ideal.
                 </p>
               </div>
            )}

            {isLoading && (
              <div className="flex items-center gap-2 text-kayso-orange py-4">
                <Loader2 className="animate-spin" size={20} />
                <span className="text-xs font-bold uppercase">Pensando el maridaje...</span>
              </div>
            )}

            {response && (
              <div className="animate-fade-in">
                 <div className="bg-kayso-orange/10 border border-kayso-orange/20 p-4 rounded-xl text-white text-sm leading-relaxed shadow-inner">
                   {response}
                 </div>
                 <button 
                  onClick={() => setResponse(null)}
                  className="mt-3 text-[10px] text-gray-500 hover:text-white uppercase font-bold tracking-widest transition-colors"
                 >
                   Hacer otra pregunta
                 </button>
              </div>
            )}
          </div>

          {/* Footer Input */}
          <form onSubmit={handleSubmit} className="p-4 bg-gray-900 border-t border-gray-800">
            <div className="relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ej: Tengo ganas de algo con mango..."
                className="w-full bg-gray-800 text-white rounded-xl pl-4 pr-12 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-kayso-orange border border-gray-700 placeholder:text-gray-500"
              />
              <button
                type="submit"
                disabled={isLoading || !input.trim()}
                className="absolute right-2 top-1/2 transform -translate-y-1/2 bg-kayso-orange text-white p-2 rounded-lg transition-all disabled:opacity-50 disabled:grayscale"
              >
                <Send size={16} />
              </button>
            </div>
          </form>
        </div>
      )}

      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`bg-gradient-to-br from-kayso-orange to-red-700 text-white p-4 rounded-full shadow-2xl shadow-kayso-orange/40 transition-all transform hover:scale-110 flex items-center gap-3 font-bold border-2 border-white/10 ${isOpen ? 'rotate-90' : ''}`}
      >
        {isOpen ? <X size={24} /> : (
          <>
            <MessageSquare size={24} />
            <span className="hidden md:inline pr-1">¿Qué pido hoy?</span>
          </>
        )}
      </button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { MenuPreview } from './components/MenuPreview';
import { Locations } from './components/Locations';
import { Footer } from './components/Footer';
import { HowToOrder } from './components/HowToOrder';
import { BlogSection } from './components/BlogSection';
import { ComboBuilder } from './components/ComboBuilder';
import { BlogPostView } from './components/BlogPostView';
import { Testimonials } from './components/Testimonials';
import { SushiAssistant } from './components/SushiAssistant';
import { ViewState, MenuItem, BlogPost, Testimonial } from './types';
import { fetchMenuFromSheet, fetchBlogFromSheet, fetchReviewsFromSheet } from './services/sheetService';
import { MENU_ITEMS, BLOG_POSTS, TESTIMONIALS } from './constants';

function App() {
  const [view, setView] = useState<ViewState>('HOME');
  const [menuItems, setMenuItems] = useState<MenuItem[]>(MENU_ITEMS);
  const [blogPosts, setBlogPosts] = useState<BlogPost[]>(BLOG_POSTS);
  const [reviews, setReviews] = useState<Testimonial[]>(TESTIMONIALS);
  const [loading, setLoading] = useState(true);
  const [selectedPost, setSelectedPost] = useState<BlogPost | null>(null);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [view]);

  useEffect(() => {
    const loadData = async () => {
        try {
            const [menuData, blogData, reviewsData] = await Promise.all([
                fetchMenuFromSheet(),
                fetchBlogFromSheet(),
                fetchReviewsFromSheet()
            ]);
            setMenuItems(menuData);
            setBlogPosts(blogData);
            setReviews(reviewsData);
        } catch (e) {
            console.error("Using fallback data", e);
        } finally {
            setLoading(false);
        }
    };
    loadData();
  }, []);

  const handleOpenPost = (post: BlogPost) => {
    setSelectedPost(post);
    setView('BLOG_POST');
  };

  return (
    <div className="min-h-screen bg-kayso-dark flex flex-col font-sans selection:bg-kayso-orange selection:text-white">
      <Navbar currentView={view} setView={setView} />

      <main className="flex-grow">
        {view === 'HOME' && (
          <>
            <Hero onViewMenu={() => setView('MENU')} onOpenBuilder={() => setView('BUILDER')} />
            <MenuPreview items={menuItems} onOpenBuilder={() => setView('BUILDER')} loading={loading} />
            <HowToOrder />
            <Testimonials items={reviews} />
            <BlogSection posts={blogPosts} onPostClick={handleOpenPost} />
          </>
        )}

        {view === 'MENU' && (
          <div className="pt-10 pb-20 animate-fade-in">
            <div className="text-center mb-10 px-4">
              <h1 className="text-5xl font-black text-white mb-2 font-display uppercase tracking-tighter">Nuestro Menú</h1>
              <p className="text-gray-400 font-light text-xl">Calidad premium en cada pieza</p>
            </div>
            <MenuPreview fullMenu={true} items={menuItems} onOpenBuilder={() => setView('BUILDER')} loading={loading} />
          </div>
        )}

        {view === 'LOCATIONS' && (
          <div className="pt-10 animate-fade-in">
             <Locations />
          </div>
        )}

        {view === 'BLOG' && (
          <div className="pt-10 pb-20 animate-fade-in">
             <div className="text-center mb-10 px-4">
              <h1 className="text-5xl font-black text-white mb-2 font-display uppercase tracking-tighter">Blog Kayso</h1>
              <p className="text-gray-400 font-light text-xl">Noticias, novedades y cultura sushi</p>
            </div>
            <BlogSection posts={blogPosts} onPostClick={handleOpenPost} />
          </div>
        )}

        {view === 'BLOG_POST' && selectedPost && (
          <BlogPostView post={selectedPost} onBack={() => setView('BLOG')} />
        )}

        {view === 'BUILDER' && (
          <ComboBuilder menuItems={menuItems} />
        )}
      </main>

      <SushiAssistant menuItems={menuItems} />
      <Footer />
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { COMBO_SIZES, WHATSAPP_GELLY, WHATSAPP_PERON, BUILDER_UPSELLS } from '../constants';
import { ComboSize, MenuItem, Category } from '../types';
import { Check, ChevronRight, Minus, Plus, ShoppingCart, ArrowLeft, Star, Heart } from 'lucide-react';

interface ComboBuilderProps {
  menuItems?: MenuItem[];
}

export const ComboBuilder: React.FC<ComboBuilderProps> = ({ menuItems = [] }) => {
  // State
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [selectedSize, setSelectedSize] = useState<ComboSize | null>(null);
  const [selectedRolls, setSelectedRolls] = useState<{ [key: string]: number }>({});
  const [selectedExtras, setSelectedExtras] = useState<{ [key: string]: number }>({});

  // Scroll to top when step changes
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [step]);

  // --- DYNAMIC DATA PREPARATION ---

  // 1. Filter Rolls for Builder (Exclude Combos, Drinks, etc.)
  const availableRolls = useMemo(() => {
    // STRICT allowed categories (No Specials, No Nigiri, No Geishas)
    // Only 'Nuestros Rolls' (ROLLS) and 'Vegetarianos' (VEGGIE)
    const allowedCategories = [Category.ROLLS, Category.VEGGIE];

    // Normalize string for loose comparison (remove accents, lowercase, trim)
    const normalize = (str: string) => str.toLowerCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

    const allowedSet = new Set(allowedCategories.map(c => normalize(c)));

    // Sort logic: Alphabetical
    return menuItems
      .filter(item => {
          const itemCat = normalize(item.category);
          const nameLower = normalize(item.name);
          const descLower = normalize(item.description);

          // Primary Category Check
          if (!allowedSet.has(itemCat)) return false;

          // Secondary Security Check: Explicitly exclude non-rolls and items of 6 units
          if (
              nameLower.includes('niguiri') || 
              nameLower.includes('geisha') || 
              nameLower.includes('sashimi') || 
              nameLower.includes('temaki') ||
              nameLower.includes('combinado') ||
              // Exclude anything mentioning 6 units
              nameLower.includes('6u') || 
              nameLower.includes('6 u') || 
              nameLower.includes('6 piezas') || 
              nameLower.includes('6 unidades') ||
              descLower.includes('6u') || 
              descLower.includes('6 u') || 
              descLower.includes('6 piezas') || 
              descLower.includes('6 unidades')
          ) {
            return false;
          }

          return true;
      })
      .map(item => {
        // Clean name: Remove (10u), (x10), etc. to avoid confusion
        const cleanName = item.name.replace(/\s*\(\s*[xX]?\d+\s*[uU]?\s*\)/gi, '').trim();

        return {
          id: item.id,
          name: cleanName,
          description: item.description,
          image: item.image,
          isPremium: false, // Per client request: Standard rolls, price handled by combo base price
          extraPrice: 0
        };
      })
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [menuItems]);

  // 2. Extras are now fixed High-Margin Upsells from constants
  const availableExtras = BUILDER_UPSELLS;


  // Computed Values
  const totalRollsSelected = (Object.values(selectedRolls) as number[]).reduce((a, b) => a + b, 0);
  const isSelectionComplete = selectedSize ? totalRollsSelected >= selectedSize.slots : false;

  const totalPrice = useMemo(() => {
    let total = 0;
    if (selectedSize) total += selectedSize.basePrice;

    // Add premium roll costs (if any logic is re-enabled later)
    Object.entries(selectedRolls).forEach(([rollId, count]: [string, number]) => {
      const roll = availableRolls.find(r => String(r.id) === String(rollId));
      if (roll && roll.extraPrice) {
        total += roll.extraPrice * count; 
      }
    });

    // Add extras
    Object.entries(selectedExtras).forEach(([extraId, count]: [string, number]) => {
      const extra = availableExtras.find(e => String(e.id) === String(extraId));
      if (extra) {
        total += extra.price * count;
      }
    });

    return total;
  }, [selectedSize, selectedRolls, selectedExtras, availableRolls, availableExtras]);

  // Handlers
  const handleSelectSize = (size: ComboSize) => {
    setSelectedSize(size);
    setSelectedRolls({}); // Reset rolls on size change
    setStep(2);
  };

  const handleUpdateRoll = (rollId: string, delta: number) => {
    if (!selectedSize) return;

    const currentCount = selectedRolls[rollId] || 0;
    const newCount = currentCount + delta;

    if (newCount < 0) return;
    if (delta > 0 && totalRollsSelected >= selectedSize.slots) return; // Limit reached

    const newSelection = { ...selectedRolls };
    if (newCount === 0) {
      delete newSelection[rollId];
    } else {
      newSelection[rollId] = newCount;
    }
    setSelectedRolls(newSelection);
  };

  const handleUpdateExtra = (extraId: string, delta: number) => {
    const currentCount = selectedExtras[extraId] || 0;
    const newCount = currentCount + delta;

    if (newCount < 0) return;

    const newSelection = { ...selectedExtras };
    if (newCount === 0) {
      delete newSelection[extraId];
    } else {
      newSelection[extraId] = newCount;
    }
    setSelectedExtras(newSelection);
  };

  const generateWhatsAppMessage = () => {
    if (!selectedSize) return '';

    let message = `Hola Kayso! 👋 Quiero pedir un combo personalizado: \n\n`;
    message += `*Base:* ${selectedSize.pieces} Piezas ($${selectedSize.basePrice})\n`;

    message += `\n*Rolls Elegidos (x5u c/u):* \n`;
    Object.entries(selectedRolls).forEach(([rollId, count]: [string, number]) => {
      // Fix: Ensure comparison works even if IDs are numbers in Excel
      const roll = availableRolls.find(r => String(r.id) === String(rollId));
      if (roll) message += `- ${count}x ${roll.name} ${roll.extraPrice ? '(+$' + roll.extraPrice + ' c/u)' : ''}\n`;
    });

    const upsells = Object.entries(selectedExtras);
    if (upsells.length > 0) {
      message += `\n*Adicionales:* \n`;
      upsells.forEach(([id, count]: [string, number]) => {
        const item = availableExtras.find(e => String(e.id) === String(id));
        if(item) message += `- ${count}x ${item.name} ($${item.price})\n`;
      });
    }

    message += `\n*TOTAL ESTIMADO: $${totalPrice.toLocaleString()}*`;
    message += `\n\nGracias!`;

    return encodeURIComponent(message);
  };

  // Render Functions
  const renderStep1 = () => (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-fade-in">
      {COMBO_SIZES.map(size => (
        <button
          key={size.id}
          onClick={() => handleSelectSize(size)}
          className="group bg-gray-800 border-2 border-gray-700 hover:border-kayso-orange rounded-2xl p-8 transition-all text-left relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 bg-gray-700 text-gray-400 text-xs font-bold px-3 py-1 rounded-bl-xl group-hover:bg-kayso-orange group-hover:text-white transition-colors">
            {size.slots} Gustos
          </div>
          <h3 className="text-3xl font-bold font-display text-white mb-2">{size.pieces} <span className="text-xl font-normal font-sans text-gray-400">Piezas</span></h3>
          <p className="text-kayso-orange font-bold font-display text-2xl mb-4">${size.basePrice.toLocaleString()}</p>
          <p className="text-gray-400 text-sm">Ideal para {Math.round((size.pieces as number) / 15)} personas aprox.</p>
        </button>
      ))}
    </div>
  );

  const renderStep2 = () => (
    <div className="animate-fade-in">
      <div className="bg-gray-800/50 border border-kayso-orange/30 rounded-xl p-4 mb-6 flex justify-between items-center sticky top-20 z-30 backdrop-blur-md shadow-lg">
        <div>
          <p className="text-gray-400 text-sm uppercase font-bold tracking-wider">Elegí tus rolls</p>
          <p className="text-white font-bold font-display">
            {totalRollsSelected} / {selectedSize?.slots} Seleccionados
          </p>
        </div>
        <div className="h-2 w-32 bg-gray-700 rounded-full overflow-hidden">
          <div 
            className={`h-full transition-all duration-500 ${isSelectionComplete ? 'bg-green-500' : 'bg-kayso-orange'}`}
            style={{ width: `${selectedSize ? (totalRollsSelected / selectedSize.slots) * 100 : 0}%` }}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {availableRolls.map(roll => {
           const count = selectedRolls[roll.id] || 0;
           const isMaxed = totalRollsSelected >= (selectedSize?.slots || 0);

           return (
            <div key={roll.id} className={`bg-gray-800 rounded-xl p-4 border ${count > 0 ? 'border-kayso-orange' : 'border-gray-700'} flex gap-4 transition-all`}>
              <img 
                src={roll.image} 
                alt={roll.name} 
                loading="lazy" 
                decoding="async"
                className="w-20 h-20 rounded-lg object-cover bg-gray-700" 
              />
              <div className="flex-1 flex flex-col justify-between">
                <div>
                  <div className="flex justify-between items-start">
                    <h4 className="font-bold font-display text-white text-sm">{roll.name}</h4>
                    {roll.isPremium && <span className="text-xs text-yellow-500 font-bold border border-yellow-500/30 px-1 rounded">+${roll.extraPrice}</span>}
                  </div>

                  {/* Badge for 5 units */}
                  <div className="mt-1 mb-1">
                    <span className="bg-gray-700/50 text-gray-300 text-[10px] uppercase font-bold px-2 py-0.5 rounded border border-gray-600/50">
                      5 Unidades
                    </span>
                  </div>

                  <p className="text-gray-400 text-xs line-clamp-2">{roll.description}</p>
                </div>

                <div className="flex items-center justify-end gap-3 mt-2">
                  {count > 0 && (
                    <>
                       <button onClick={() => handleUpdateRoll(roll.id, -1)} className="w-8 h-8 rounded-full bg-gray-700 text-white flex items-center justify-center hover:bg-gray-600"><Minus size={14} /></button>
                       <span className="font-bold text-white">{count}</span>
                    </>
                  )}
                  <button 
                    onClick={() => handleUpdateRoll(roll.id, 1)} 
                    disabled={isMaxed}
                    className={`w-8 h-8 rounded-full flex items-center justify-center transition-colors ${isMaxed ? 'bg-gray-700 text-gray-500 cursor-not-allowed' : 'bg-kayso-orange text-white hover:bg-orange-600'}`}
                  >
                    <Plus size={14} />
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Spacer for bottom bar */}
      <div className="h-24"></div>
    </div>
  );

  const renderStep3 = () => (
    <div className="animate-fade-in">
       <div className="max-w-2xl mx-auto">

          <div className="text-center mb-8">
            <div className="flex items-center justify-center gap-2 mb-2">
              <Star size={24} className="text-kayso-orange" fill="currentColor" />
              <h3 className="text-2xl font-bold font-display text-white">Adicionales</h3>
            </div>
            <p className="text-gray-400">Completá tu pedido con estos extras.</p>
          </div>

          <div className="space-y-4">
            {availableExtras.map(item => (
              <div key={item.id} className="flex justify-between items-center bg-gray-800 p-5 rounded-xl border border-gray-700 hover:border-kayso-orange/50 transition-colors">
                <div className="flex items-center gap-4">
                  {item.name.toLowerCase().includes('salsa') ? <Heart className="text-red-500" size={20} /> : <Star className="text-yellow-500" size={20} />}
                  <div>
                    <p className="text-white font-bold">{item.name}</p>
                    <p className="text-kayso-orange text-sm font-bold">+${item.price}</p>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                    {selectedExtras[item.id] > 0 && (
                      <button onClick={() => handleUpdateExtra(item.id, -1)} className="w-8 h-8 rounded-full bg-gray-700 text-white flex items-center justify-center hover:bg-gray-600"><Minus size={14} /></button>
                    )}
                    <span className={`font-bold w-6 text-center ${selectedExtras[item.id] > 0 ? 'text-white' : 'text-gray-600'}`}>{selectedExtras[item.id] || 0}</span>
                    <button onClick={() => handleUpdateExtra(item.id, 1)} className="w-8 h-8 rounded-full bg-kayso-orange text-white flex items-center justify-center hover:bg-orange-600"><Plus size={14} /></button>
                </div>
              </div>
            ))}
          </div>

           {/* Spacer for bottom bar */}
           <div className="h-24"></div>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-kayso-dark pt-8 pb-32">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* Header */}
        <div className="mb-8">
            <button 
              onClick={() => {
                if(step === 1) return; 
                setStep(step === 3 ? 2 : 1);
              }}
              className={`flex items-center gap-2 text-gray-400 hover:text-white mb-4 transition-colors ${step === 1 ? 'invisible' : ''}`}
            >
              <ArrowLeft size={16} /> Volver
            </button>
            <h1 className="text-4xl font-bold font-display text-white mb-2">
              Armá tu <span className="text-kayso-orange">Combo</span>
            </h1>
            <p className="text-gray-400">Diseñá tu tabla perfecta en 3 pasos.</p>
        </div>

        {/* Steps Progress */}
        <div className="flex items-center mb-12">
          {[1, 2, 3].map((s) => (
             <div key={s} className="flex items-center flex-1 last:flex-none">
               <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold font-display border-2 transition-all ${
                 step >= s 
                  ? 'bg-kayso-orange border-kayso-orange text-white' 
